import fs from 'fs';
import path from 'path';
import { GENERATOR_NAME } from '../sensitive-fields-generator.js';

/**
 * Generate enhanced security utility functions
 * Supports multiple annotation types and security levels
 */
export async function generateSecurityUtilities(outputDir, fieldMetadataMap) {
  const modelNames = Object.keys(fieldMetadataMap);

  const scalarFieldEnumMap = modelNames
    .map((modelName) => `  ${modelName}: Prisma.${modelName}ScalarFieldEnum;`)
    .join('\n');

  const utilityFunctions = `// Generated by ${GENERATOR_NAME}
// DO NOT EDIT - This file is automatically generated
/* eslint-disable @typescript-eslint/no-explicit-any */
/* eslint-disable @typescript-eslint/no-unused-vars */

import type { Prisma } from '../client';
import { 
  allSensitiveFields, 
  allFieldsBySecurityLevel,
  SecurityLevel,
  GDPR_CATEGORIES,
  GDPR_PURPOSES,
  GDPR_RETENTION_PERIODS
} from './sensitive-fields';

type ScalarFieldEnumByModel = {
${scalarFieldEnumMap}
};

type ModelKey = keyof typeof allSensitiveFields;
type AnyModel = Prisma.ModelName;
type FieldNameForModel<M extends AnyModel> = M extends keyof ScalarFieldEnumByModel
  ? ScalarFieldEnumByModel[M]
  : string;
type UserRole = 'ADMIN' | 'MODERATOR' | 'EXPERT' | 'USER' | 'ANONYMOUS';

/**
 * Check if a field has a specific security level for a given model
 * 
 * @param modelName - The name of the model to check
 * @param fieldName - The name of the field to check
 * @param securityLevel - The security level to check for
 * @returns True if the field has the specified security level
 */
export const hasSecurityLevel = <M extends AnyModel>(
  modelName: M,
  fieldName: FieldNameForModel<M>,
  securityLevel: SecurityLevel
): boolean => {
  const modelFields = allFieldsBySecurityLevel[modelName as string];
  if (!modelFields) return securityLevel === 'public';
  
  const fields = modelFields[securityLevel === 'admin-only' ? 'adminOnly' : securityLevel === 'never-expose' ? 'neverExpose' : securityLevel];
  return fields.includes(fieldName as string);
}

/**
 * Check if a field is marked as sensitive for a given model (legacy compatibility)
 * 
 * @param modelName - The name of the model to check
 * @param fieldName - The name of the field to check
 * @returns True if the field is sensitive, false otherwise
 */
export const isSensitiveField = <M extends AnyModel>(
  modelName: M,
  fieldName: FieldNameForModel<M>
): boolean => {
  return hasSecurityLevel(modelName, fieldName, 'sensitive');
}

/**
 * Check if a field should never be exposed for a given model
 * 
 * @param modelName - The name of the model to check
 * @param fieldName - The name of the field to check
 * @returns True if the field should never be exposed
 */
export const isNeverExposeField = <M extends AnyModel>(
  modelName: M,
  fieldName: FieldNameForModel<M>
): boolean => {
  return hasSecurityLevel(modelName, fieldName, 'never-expose');
}

/**
 * Check if a field is admin-only for a given model
 * 
 * @param modelName - The name of the model to check
 * @param fieldName - The name of the field to check
 * @returns True if the field is admin-only
 */
export const isAdminOnlyField = <M extends AnyModel>(
  modelName: M,
  fieldName: FieldNameForModel<M>
): boolean => {
  return hasSecurityLevel(modelName, fieldName, 'admin-only');
}

/**
 * Get the security level of a field
 * 
 * @param modelName - The name of the model
 * @param fieldName - The name of the field
 * @returns The security level of the field
 */
export const getFieldSecurityLevel = <M extends AnyModel>(
  modelName: M,
  fieldName: FieldNameForModel<M>
): SecurityLevel => {
  if (hasSecurityLevel(modelName, fieldName, 'never-expose')) return 'never-expose';
  if (hasSecurityLevel(modelName, fieldName, 'admin-only')) return 'admin-only';
  if (hasSecurityLevel(modelName, fieldName, 'sensitive')) return 'sensitive';
  return 'public';
}

/**
 * Get all sensitive fields for a model
 * 
 * @param modelName - The name of the model to get the sensitive fields for
 * @returns The sensitive fields for the model
 */
export const getSensitiveFields = <M extends AnyModel>(
  modelName: M
): M extends ModelKey ? (typeof allSensitiveFields)[M] : readonly string[] => {
  const map = allSensitiveFields as unknown as Record<string, readonly string[]>;
  return (map[modelName as string] ?? []) as any;
}

/**
 * Remove fields based on security level from an object
 * 
 * @param obj - The object to filter
 * @param modelName - The name of the model
 * @param excludeSecurityLevels - Security levels to exclude
 * @returns The object with specified security level fields removed
 */
export const omitFieldsBySecurityLevel = <
  T extends Record<string, unknown>,
  M extends AnyModel
>(
  obj: T,
  modelName: M,
  excludeSecurityLevels: SecurityLevel[] = ['sensitive', 'admin-only', 'never-expose']
): T => {
  const result = { ...obj } as T;
  const modelFields = allFieldsBySecurityLevel[modelName as string];
  
  if (!modelFields) return result;
  
  excludeSecurityLevels.forEach(level => {
    const fieldsToRemove = modelFields[level === 'admin-only' ? 'adminOnly' : level === 'never-expose' ? 'neverExpose' : level] || [];
    fieldsToRemove.forEach(fieldName => {
      delete (result as Record<string, unknown>)[fieldName];
    });
  });
  
  return result;
}

/**
 * Remove sensitive fields from an object (field omission pattern) - Legacy compatibility
 * 
 * @param obj - The object to remove sensitive fields from
 * @param modelName - The name of the model to remove sensitive fields from
 * @returns The object with sensitive fields removed
 */
export const omitSensitiveFields = <
  T extends Record<string, unknown>,
  M extends AnyModel
>(
  obj: T,
  modelName: M
): M extends ModelKey ? Omit<T, (typeof allSensitiveFields)[M][number]> : T => {
  return omitFieldsBySecurityLevel(obj, modelName, ['sensitive']) as any;
}

/**
 * Remove never-expose fields from an object
 * 
 * @param obj - The object to filter
 * @param modelName - The name of the model
 * @returns The object with never-expose fields removed
 */
export const omitNeverExposeFields = <
  T extends Record<string, unknown>,
  M extends AnyModel
>(
  obj: T,
  modelName: M
): T => {
  return omitFieldsBySecurityLevel(obj, modelName, ['never-expose']);
}

/**
 * Remove admin-only fields from an object
 * 
 * @param obj - The object to filter
 * @param modelName - The name of the model
 * @returns The object with admin-only fields removed
 */
export const omitAdminOnlyFields = <
  T extends Record<string, unknown>,
  M extends AnyModel
>(
  obj: T,
  modelName: M
): T => {
  return omitFieldsBySecurityLevel(obj, modelName, ['admin-only']);
}

/**
 * Pick only non-sensitive fields from an object (safe field picking)
 * 
 * @param obj - The object to pick safe fields from
 * @param modelName - The name of the model to pick safe fields from
 * @param allowedSensitiveFields - The fields that are explicitly allowed to be sensitive
 * @returns The object with only the safe fields
 */
export const pickSafeFields = <
  T extends Record<string, unknown>,
  M extends AnyModel
>(
  obj: T,
  modelName: M,
  allowedSensitiveFields: Array<FieldNameForModel<M>> = []
): Partial<T> => {
  const sensitiveFields = getSensitiveFields(modelName) as readonly string[];
  const result: Partial<T> = {};
  
  Object.keys(obj).forEach((key) => {
    const fieldName = key as keyof T;

    const isSensitive = (sensitiveFields as readonly string[]).includes(key);
    const isExplicitlyAllowed = (allowedSensitiveFields as readonly string[]).includes(key);
    
    if (!isSensitive || isExplicitlyAllowed) {
      result[fieldName] = obj[fieldName];
    }
  });
  
  return result;
}

/**
 * Get allowed fields for a user role based on security levels
 * 
 * @param modelName - The name of the model
 * @param userRole - The role of the user
 * @returns Object with allowed and excluded fields
 */
export const getRoleBasedFieldAccess = <M extends AnyModel>(
  modelName: M,
  userRole: UserRole = 'ANONYMOUS'
) => {
  const modelFields = allFieldsBySecurityLevel[modelName as string];
  
  if (!modelFields) {
    return {
      allowedFields: [],
      excludedSecurityLevels: [] as SecurityLevel[]
    };
  }
  
  // Define which security levels each role can access
  const roleSecurityAccess: Record<UserRole, SecurityLevel[]> = {
    ADMIN: ['public', 'sensitive', 'admin-only'], // Admin can see everything except never-expose
    MODERATOR: ['public', 'sensitive'], // Moderator can see sensitive but not admin-only
    EXPERT: ['public', 'sensitive'], // Expert can see sensitive content
    USER: ['public'], // User can only see public fields
    ANONYMOUS: ['public'], // Anonymous can only see public fields
  };
  
  const allowedLevels = roleSecurityAccess[userRole] || ['public'];
  const excludedLevels = (['public', 'sensitive', 'admin-only', 'never-expose'] as SecurityLevel[])
    .filter(level => !allowedLevels.includes(level));
  
  // Never-expose fields are always excluded
  if (!excludedLevels.includes('never-expose')) {
    excludedLevels.push('never-expose');
  }
  
  return {
    allowedSecurityLevels: allowedLevels,
    excludedSecurityLevels: excludedLevels
  };
}

/**
 * Create a type-safe field selector based on user permissions
 * 
 * @param modelName - The name of the model to create a secure selector for
 * @param userRole - The role of the user to create a secure selector for
 * @returns A secure selector for the model
 */
export const createSecureSelector = <M extends AnyModel>(
  modelName: M,
  userRole: UserRole = 'ANONYMOUS'
) => {
  const { excludedSecurityLevels } = getRoleBasedFieldAccess(modelName, userRole);
  
  return {
    // Enhanced filtering by security level
    filterByRole: <T extends Record<string, unknown>>(obj: T) => 
      omitFieldsBySecurityLevel(obj, modelName, excludedSecurityLevels),
    
    // Legacy compatibility functions
    omitSensitive: <T extends Record<string, unknown>>(obj: T) => 
      omitSensitiveFields(obj, modelName),
    
    pickSafe: <T extends Record<string, unknown>>(obj: T) => 
      pickSafeFields(obj, modelName, []),
      
    // Field checking functions
    isSensitive: (fieldName: FieldNameForModel<M>) => 
      isSensitiveField(modelName, fieldName),
      
    isNeverExpose: (fieldName: FieldNameForModel<M>) => 
      isNeverExposeField(modelName, fieldName),
      
    isAdminOnly: (fieldName: FieldNameForModel<M>) => 
      isAdminOnlyField(modelName, fieldName),
      
    getSecurityLevel: (fieldName: FieldNameForModel<M>) => 
      getFieldSecurityLevel(modelName, fieldName),
      
    // Role access information
    getRoleAccess: () => getRoleBasedFieldAccess(modelName, userRole),
  };
}
`;

  fs.writeFileSync(path.join(outputDir, 'security-utils.ts'), utilityFunctions);
}
